 3→import React, { useState } from 'react';
 4→import { Copy, Check } from 'lucide-react';
 5→import { cn } from '@/lib/utils';
 6→
 7→interface CodeBlockProps {
 8→  code: string;
 9→  language?: string;
10→  title?: string;
11→  className?: string;
12→}
13→
14→export function CodeBlock({ code, language, title, className }: CodeBlockProps) {
15→  const [copied, setCopied] = useState(false);
16→
17→  const handleCopy = () => {
18→    navigator.clipboard.writeText(code);
19→    setCopied(true);
20→    setTimeout(() => setCopied(false), 2000);
21→  };
22→
23→  return (
24→    <div className={cn("rounded-xl border border-white/10 overflow-hidden", className)}>
25→      {(title || language) && (
26→        <div className="flex items-center justify-between px-4 py-2.5 bg-white/[0.03] border-b border-white/5">
27→          <div className="flex items-center gap-2">
28→            {title && <span className="text-xs font-medium text-white/60">{title}</span>}
29→            {language && (
30→              <span className="text-[10px] px-2 py-0.5 bg-white/5 rounded-full text-white/40 uppercase">{language}</span>
31→            )}
32→          </div>
33→          <button
34→            onClick={handleCopy}
35→            className="flex items-center gap-1.5 px-2 py-1 rounded-lg text-xs text-white/40 hover:text-white/70 hover:bg-white/5 transition-colors"
36→          >
37→            {copied ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
38→            {copied ? 'Copie !' : 'Copier'}
39→          </button>
40→        </div>
41→      )}
42→      <pre className="p-4 overflow-x-auto bg-[#0d0f12]">
43→        <code className="text-sm text-white/70 font-mono leading-relaxed whitespace-pre">
44→          {code}
45→        </code>
46→      </pre>
47→    </div>
48→  );
49→}
