  3→import * as React from "react"
  4→import { cn } from "@/lib/utils"
  5→
  6→interface TabsProps {
  7→  value: string
  8→  onValueChange: (value: string) => void
  9→  children: React.ReactNode
 10→  className?: string
 11→}
 12→
 13→function Tabs({ value, onValueChange, children, className }: TabsProps) {
 14→  return (
 15→    <div className={cn("", className)} data-active-tab={value}>
 16→      {React.Children.map(children, (child) => {
 17→        if (React.isValidElement(child)) {
 18→          return React.cloneElement(child as React.ReactElement<any>, {
 19→            activeTab: value,
 20→            onTabChange: onValueChange,
 21→          })
 22→        }
 23→        return child
 24→      })}
 25→    </div>
 26→  )
 27→}
 28→
 29→interface TabsListProps extends React.HTMLAttributes<HTMLDivElement> {
 30→  activeTab?: string
 31→  onTabChange?: (value: string) => void
 32→}
 33→
 34→function TabsList({ className, children, activeTab, onTabChange, ...props }: TabsListProps) {
 35→  return (
 36→    <div
 37→      className={cn(
 38→        "inline-flex items-center gap-1 rounded-xl bg-white/5 p-1",
 39→        className
 40→      )}
 41→      role="tablist"
 42→      {...props}
 43→    >
 44→      {React.Children.map(children, (child) => {
 45→        if (React.isValidElement(child)) {
 46→          return React.cloneElement(child as React.ReactElement<any>, {
 47→            activeTab,
 48→            onTabChange,
 49→          })
 50→        }
 51→        return child
 52→      })}
 53→    </div>
 54→  )
 55→}
 56→
 57→interface TabsTriggerProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
 58→  value: string
 59→  activeTab?: string
 60→  onTabChange?: (value: string) => void
 61→}
 62→
 63→function TabsTrigger({ className, value, activeTab, onTabChange, children, ...props }: TabsTriggerProps) {
 64→  const isActive = activeTab === value
 65→
 66→  return (
 67→    <button
 68→      role="tab"
 69→      aria-selected={isActive}
 70→      className={cn(
 71→        "inline-flex items-center justify-center whitespace-nowrap rounded-lg px-3 py-1.5 text-sm font-medium transition-all",
 72→        isActive
 73→          ? "bg-primary text-primary-foreground shadow-sm"
 74→          : "text-white/50 hover:text-white/80 hover:bg-white/5",
 75→        className
 76→      )}
 77→      onClick={() => onTabChange?.(value)}
 78→      {...props}
 79→    >
 80→      {children}
 81→    </button>
 82→  )
 83→}
 84→
 85→interface TabsContentProps extends React.HTMLAttributes<HTMLDivElement> {
 86→  value: string
 87→  activeTab?: string
 88→}
 89→
 90→function TabsContent({ className, value, activeTab, children, ...props }: TabsContentProps) {
 91→  if (activeTab !== value) return null
 92→
 93→  return (
 94→    <div
 95→      role="tabpanel"
 96→      className={cn("mt-4", className)}
 97→      {...props}
 98→    >
 99→      {children}
100→    </div>
101→  )
102→}
103→
104→export { Tabs, TabsList, TabsTrigger, TabsContent }
