 4→interface ProgressBarProps {
 5→  value: number;
 6→  max?: number;
 7→  label?: string;
 8→  showValue?: boolean;
 9→  size?: 'sm' | 'md' | 'lg';
10→  className?: string;
11→}
12→
13→export function ProgressBar({ value, max = 100, label, showValue = false, size = 'md', className }: ProgressBarProps) {
14→  const percentage = Math.min(Math.max((value / max) * 100, 0), 100);
15→
16→  const getColor = () => {
17→    if (percentage >= 80) return 'bg-emerald-500';
18→    if (percentage >= 60) return 'bg-amber-500';
19→    if (percentage >= 40) return 'bg-orange-500';
20→    return 'bg-red-500';
21→  };
22→
23→  const heights = {
24→    sm: 'h-1.5',
25→    md: 'h-2',
26→    lg: 'h-3',
27→  };
28→
29→  return (
30→    <div className={cn("w-full", className)}>
31→      {(label || showValue) && (
32→        <div className="flex items-center justify-between mb-1.5">
33→          {label && <span className="text-xs text-white/50">{label}</span>}
34→          {showValue && (
35→            <span className="text-xs font-medium text-white/70">{Math.round(percentage)}%</span>
36→          )}
37→        </div>
38→      )}
39→      <div className={cn("w-full bg-white/5 rounded-full overflow-hidden", heights[size])}>
40→        <div
41→          className={cn("h-full rounded-full transition-all duration-700 ease-out", getColor())}
42→          style={{ width: `${percentage}%` }}
43→        />
44→      </div>
45→    </div>
46→  );
47→}
