'use client';

import { useState } from 'react';
import {
  Search,
  ShieldCheck,
  TrendingUp,
  Sparkles,
  Globe,
  Loader2,
  CheckCircle,
  ArrowRight,
} from 'lucide-react';
import { PageHeader } from '@/components/page-header';
import ScoreRing from '@/components/ScoreRing';
import CategoryCard from '@/components/CategoryCard';
import { MOCK_ANALYSIS_RESULT, MOCK_RECOMMENDATIONS } from '@/lib/mock-data';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card } from '@/components/ui/card';

type AnalysisStep = {
  label: string;
  description: string;
};

const ANALYSIS_STEPS: AnalysisStep[] = [
  { label: 'Crawling', description: 'Exploration des pages et du contenu...' },
  { label: 'Analyzing', description: 'Analyse des criteres AEO (50+ signaux)...' },
  { label: 'Scoring', description: 'Calcul du score global et par categorie...' },
  { label: 'Generating', description: 'Generation des recommandations...' },
];

export default function AnalyzePage() {
  const [url, setUrl] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [currentStep, setCurrentStep] = useState(-1);
  const [showResults, setShowResults] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!url || isAnalyzing) return;

    setIsAnalyzing(true);
    setShowResults(false);
    setCurrentStep(0);

    // Simulate progress through 4 steps
    const stepDelays = [1200, 1500, 1000, 800];
    let elapsed = 0;

    stepDelays.forEach((delay, index) => {
      elapsed += delay;
      setTimeout(() => {
        setCurrentStep(index + 1);
      }, elapsed);
    });

    // Final delay after all steps, show results
    setTimeout(() => {
      setIsAnalyzing(false);
      setCurrentStep(-1);
      setShowResults(true);
    }, elapsed + 600);
  };

  const result = MOCK_ANALYSIS_RESULT;
  const categories = Object.values(result.categories);

  return (
    <div className="p-4 sm:p-8 max-w-7xl mx-auto">
      <PageHeader
        title="Analysez votre visibilite IA"
        description="Decouvrez comment les moteurs de reponse percoivent votre contenu et obtenez un plan d'action pour etre cite."
        breadcrumbs={[
          { label: 'App', href: '/app' },
          { label: 'Analyse AEO' },
        ]}
      />

      {/* URL Input Section */}
      <div className="animate-fade-in-up">
        <div className="relative max-w-3xl mx-auto mb-12">
          {/* Glow effect */}
          <div className="absolute inset-0 bg-primary/20 blur-3xl rounded-full opacity-20 -z-10" />

          <form onSubmit={handleSubmit}>
            <div className="flex items-center p-2 bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl transition-all focus-within:border-primary/50 focus-within:bg-white/10 focus-within:ring-1 focus-within:ring-primary/20">
              <Search className="text-gray-400 ml-4 shrink-0" size={24} />
              <input
                type="url"
                required
                placeholder="https://votre-site.com"
                className="w-full bg-transparent border-none focus:ring-0 focus:outline-none text-white placeholder-gray-500 text-lg px-4 py-4"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                disabled={isAnalyzing}
              />
              <Button
                type="submit"
                size="lg"
                disabled={isAnalyzing}
                className="px-8 shrink-0 font-semibold"
              >
                {isAnalyzing ? (
                  <>
                    <Loader2 className="animate-spin" size={18} />
                    Analyse...
                  </>
                ) : (
                  "Lancer l'audit"
                )}
              </Button>
            </div>
          </form>

          <div className="flex justify-center gap-8 mt-6 text-sm text-gray-500">
            <span className="flex items-center gap-2">
              <ShieldCheck size={16} className="text-emerald-500" /> Analyse Securisee
            </span>
            <span className="flex items-center gap-2">
              <TrendingUp size={16} className="text-amber-500" /> +50 Criteres GEO
            </span>
          </div>
        </div>
      </div>

      {/* Progress Animation */}
      {isAnalyzing && (
        <div className="max-w-2xl mx-auto mb-12 animate-fade-in-up">
          <Card className="p-8">
            <div className="flex items-center gap-3 mb-6">
              <Globe size={20} className="text-primary" />
              <span className="text-white font-medium">{url}</span>
            </div>

            <div className="space-y-4">
              {ANALYSIS_STEPS.map((step, index) => {
                const isComplete = currentStep > index;
                const isCurrent = currentStep === index;

                return (
                  <div
                    key={step.label}
                    className={`flex items-center gap-4 p-3 rounded-xl transition-all duration-300 ${
                      isCurrent
                        ? 'bg-primary/10 border border-primary/20'
                        : isComplete
                        ? 'bg-white/[0.02] opacity-60'
                        : 'opacity-30'
                    }`}
                  >
                    <div className="w-8 h-8 rounded-full flex items-center justify-center shrink-0">
                      {isComplete ? (
                        <CheckCircle size={20} className="text-emerald-500" />
                      ) : isCurrent ? (
                        <Loader2 size={20} className="text-primary animate-spin" />
                      ) : (
                        <div className="w-5 h-5 rounded-full border-2 border-white/10" />
                      )}
                    </div>
                    <div>
                      <p className="text-sm font-medium text-white">{step.label}</p>
                      <p className="text-xs text-white/40">{step.description}</p>
                    </div>
                    {isCurrent && (
                      <div className="ml-auto">
                        <Badge variant="default">En cours</Badge>
                      </div>
                    )}
                    {isComplete && (
                      <div className="ml-auto">
                        <Badge variant="success">Termine</Badge>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>

            {/* Progress bar */}
            <div className="mt-6 w-full bg-white/5 rounded-full h-2 overflow-hidden">
              <div
                className="h-full bg-primary rounded-full transition-all duration-700 ease-out"
                style={{
                  width: `${Math.min(((currentStep + 1) / ANALYSIS_STEPS.length) * 100, 100)}%`,
                }}
              />
            </div>
          </Card>
        </div>
      )}

      {/* Results Section */}
      {showResults && (
        <div className="animate-fade-in-up space-y-8">
          {/* Score Overview */}
          <div className="grid lg:grid-cols-12 gap-8">
            {/* Score Ring + Summary */}
            <div className="lg:col-span-4">
              <Card className="p-8 flex flex-col items-center text-center">
                <ScoreRing score={result.globalScore} size={160} strokeWidth={10} />
                <h3 className="text-xl font-bold text-white mt-4 mb-2">Score Global AEO</h3>
                <p className="text-sm text-white/40 mb-4">
                  Votre site est analyse sur {Object.keys(result.categories).length} categories de criteres AEO.
                </p>
                <div className="flex items-center gap-2 text-xs text-white/40">
                  <Globe size={14} />
                  <span>{result.url}</span>
                </div>
              </Card>
            </div>

            {/* Category Cards */}
            <div className="lg:col-span-8">
              <div className="space-y-0">
                {categories.map((category) => (
                  <CategoryCard key={category.name} category={category} />
                ))}
              </div>
            </div>
          </div>

          {/* AI Citation Preview */}
          <Card className="p-6">
            <div className="flex items-center gap-3 mb-4">
              <div className="p-2 rounded-xl bg-primary/10 text-primary">
                <Sparkles size={20} />
              </div>
              <div>
                <h3 className="text-lg font-bold text-white">Prediction de Citation IA</h3>
                <p className="text-sm text-white/40">
                  Probabilite d'etre cite apres optimisation: {Math.round(result.aiCitation.probability * 100)}%
                </p>
              </div>
            </div>

            <div className="grid md:grid-cols-2 gap-6">
              <div className="bg-red-500/5 border border-red-500/10 rounded-xl p-4">
                <p className="text-xs font-bold text-red-400 uppercase tracking-wider mb-2">Avant optimisation</p>
                <p className="text-sm text-white/60 leading-relaxed">{result.aiCitation.before}</p>
              </div>
              <div className="bg-emerald-500/5 border border-emerald-500/10 rounded-xl p-4">
                <p className="text-xs font-bold text-emerald-400 uppercase tracking-wider mb-2">Apres optimisation</p>
                <p className="text-sm text-white/60 leading-relaxed">{result.aiCitation.after}</p>
              </div>
            </div>
          </Card>

          {/* Recommendations */}
          <div>
            <h3 className="text-xl font-serif font-bold text-white mb-4">
              Recommandations prioritaires
            </h3>
            <div className="grid md:grid-cols-2 gap-4">
              {MOCK_RECOMMENDATIONS.slice(0, 4).map((rec) => {
                const priorityColors: Record<string, string> = {
                  critical: 'border-red-500/20 bg-red-500/5',
                  high: 'border-amber-500/20 bg-amber-500/5',
                  medium: 'border-blue-500/20 bg-blue-500/5',
                  low: 'border-white/10 bg-white/[0.02]',
                };
                const priorityBadge: Record<string, 'destructive' | 'warning' | 'default' | 'secondary'> = {
                  critical: 'destructive',
                  high: 'warning',
                  medium: 'default',
                  low: 'secondary',
                };

                return (
                  <Card
                    key={rec.id}
                    className={`p-5 border ${priorityColors[rec.priority]}`}
                  >
                    <div className="flex items-start justify-between gap-3 mb-2">
                      <h4 className="text-sm font-bold text-white">{rec.title}</h4>
                      <Badge variant={priorityBadge[rec.priority]}>
                        {rec.priority}
                      </Badge>
                    </div>
                    <p className="text-xs text-white/40 mb-3">{rec.description}</p>
                    <div className="flex items-center gap-2 text-xs">
                      <span className="text-white/30">Effort:</span>
                      <Badge variant="outline" className="text-[10px]">{rec.effort}</Badge>
                      <span className="text-white/30 ml-2">Impact:</span>
                      <Badge variant="outline" className="text-[10px]">{rec.impact}</Badge>
                    </div>
                  </Card>
                );
              })}
            </div>
          </div>

          {/* CTA */}
          <div className="text-center pt-4">
            <Button size="lg" className="gap-2">
              Voir toutes les recommandations <ArrowRight size={16} />
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

export default function GenerativeToolsLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return <>{children}</>;
}

